  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }

  const comment = commentsService.createComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = commentsService.getCommentsByTask(req.params.projectId, req.params.taskId);
  res.json({ comments });
});

module.exports = router;
