      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const task = tasksService.createTask(req.params.projectId);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  let tasks = tasksService.getAllTasksByProject(req.params.projectId);
  if (req.query.status === 'done') {
    tasks = tasks.filter(task => task.status === 'done');
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;
